    cs, ce = c["span_start"], c["span_end"]
    # Check if this span is contained in any other span (excluding itself) in our list
    contained = False
    for j,d in enumerate(citations_sorted):
        if i == j:
            continue
        ds, de = d["span_start"], d["span_end"]
        if ds <= cs and ce <= de and (de - ds) > (ce - cs):
